import React, { useState } from 'react';
import { Chat } from './Chat';
import { ChannelList } from './ChannelList';

const App = () => {
  const [channels, setChannels] = useState(['General', 'Support', 'Development']);
  const [currentChannel, setCurrentChannel] = useState('General');

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="w-1/2 bg-[#C06C88] p-4 flex flex-col">
        <ChannelList channels={channels} currentChannel={currentChannel} setCurrentChannel={setCurrentChannel} />
      </div>
      <div className="w-1/2 bg-[#B7D7CD] p-4 ml-4">
        <Chat currentChannel={currentChannel} />
      </div>
    </div>
  );
};

export default App;
